#include <bits/stdc++.h>
using namespace std;
#define dbg(x) cerr<<#x" = "<<(x)<<endl;
#define ll long long
const int N=10005,mod=10000;;
int dp[N][2],n,m,cnt[N],s,t,t0;
struct node
{
	int v,w;
};
vector<node> g[N];
void topo(int u)
{
//	cout<<u<<"  : "<<dp[u][0]<<" "<<dp[u][1]<<"\n";
	for(int i=0;i<g[u].size();i++)
	{
		int v=g[u][i].v;
		dp[v][0]=(dp[u][0]+dp[v][0])%mod;
		dp[v][1]=(dp[u][0]*g[u][i].w+dp[u][1]+dp[v][1])%mod;
		cnt[v]--;
		if(cnt[v]==0) topo(v);
	}
}
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
//	freopen(".in","r",stdin);
//	freopen(".out","w",stdout);
	cin>>n>>m>>s>>t>>t0;
	for(int i=1;i<=m;i++)
	{
		int u,v,w;
		cin>>u>>v>>w;
		cnt[v]++;
		g[u].push_back(node{v,w});
	}
	dp[s][0]=1;
	topo(s);
	cout<<(dp[t][1]+(dp[t][0]-1)*t0)%mod;
	return 0;
}
